package com.example.sessionmanager

import android.content.Context

object SessionManager {

    private const val SESSION_ID_KEY = "SESSION_ID_KEY"
    private const val TOKEN_LENGTH = 32

    fun getSessionId(context: Context): String {
        val sharedPreferences = context.getSharedPreferences("SessionPrefs", Context.MODE_PRIVATE)
        var sessionId = sharedPreferences.getString(SESSION_ID_KEY, null)
        if (sessionId.isNullOrEmpty()) {
            sessionId = generateRandomAlphanumericString(TOKEN_LENGTH)
            sharedPreferences.edit().putString(SESSION_ID_KEY, sessionId).apply()
        }
        return sessionId
    }

    fun generateTemporaryToken(): String {
        return generateRandomAlphanumericString(TOKEN_LENGTH)
    }

    private fun generateRandomAlphanumericString(length: Int): String {
        val allowedChars = ('0'..'9') + ('A'..'Z') + ('a'..'z')
        return (1..length)
            .map { allowedChars.random() }
            .joinToString("")
    }
}